const body = $json.body || $json;
const site_id = body.site_id || 'sinabarimd';
const domain_map = {
  sinabarimd: 'sinabarimd.com',
  sinabari_net: 'sinabari.net',
  drsinabari: 'drsinabari.com',
  sinabariplasticsurgery: 'sinabariplasticsurgery.com',
};
return [{
  json: {
    site_id,
    domain: body.domain || domain_map[site_id] || 'sinabarimd.com',
    research_brief: body.research_brief || null,
    variation_seed: body.variation_seed || null,
    media_context: body.media_context || [],
    seo_context: body.seo_context || null,
  }
}];

// Profile YAML comes from HTTP response; original fields from Extract Fields node
const profileText = $json.data || $json.body || '';

// Parse YAML key: value lines
const fields = {};
const lines = profileText.split('\n');
let currentKey = null;
let multilineBuffer = [];
let inMultiline = false;

for (const line of lines) {
  const keyMatch = line.match(/^([\w_]+):\s*(.*)$/);
  if (keyMatch && !line.startsWith(' ') && !line.startsWith('\t')) {
    if (inMultiline && currentKey) {
      fields[currentKey] = multilineBuffer.join('\n').trim();
      multilineBuffer = [];
      inMultiline = false;
    }
    currentKey = keyMatch[1];
    const val = keyMatch[2].trim();
    if (val === '|' || val === '>') {
      inMultiline = true;
    } else {
      fields[currentKey] = val.replace(/^["']|["']$/g, '');
      currentKey = null;
    }
  } else if (inMultiline) {
    multilineBuffer.push(line.replace(/^  /, ''));
  }
}
if (inMultiline && currentKey) {
  fields[currentKey] = multilineBuffer.join('\n').trim();
}

// Pull original payload from Extract Fields node
const origin = $('Extract Fields').first().json;

return [{
  json: {
    ...origin,
    profile: fields,
  }
}];

const profile = $json.profile || {};
const site_id = $json.site_id;

const SITE_MAP = {
  sinabarimd: {
    domain: 'sinabarimd.com',
    openclawAgentId: 'publisher-sinabarimd',
    site_role: 'identity_hub',
  },
  sinabari_net: {
    domain: 'sinabari.net',
    openclawAgentId: 'publisher-sinabari-net',
    site_role: 'health_tech_authority',
  },
  drsinabari: {
    domain: 'drsinabari.com',
    openclawAgentId: 'publisher-drsinabari',
    site_role: 'editorial',
  },
  sinabariplasticsurgery: {
    domain: 'sinabariplasticsurgery.com',
    openclawAgentId: 'publisher-sinabariplasticsurgery',
    site_role: 'legacy_specialty',
  },
};

// Explicit topic overrides per site (override profile YAML if set)
const TOPIC_OVERRIDES = {
  sinabarimd: {
    allowed_topics: 'Professional identity, career highlights, selected publications, clinical leadership, medical executive perspective, Stanford training, surgical expertise',
    forbidden_topics: 'Thin blog spam, clinic impersonation, generic health tips, anything not related to Dr. Bari personally',
  },
  sinabari_net: {
    allowed_topics: 'Healthcare AI (clinical AI, hospital AI governance, AI diagnostics, AI in radiology/pathology, LLMs in medicine, AI safety in healthcare, AI workflow automation, operational AI) ~75%. Health technology broadly (medical devices, surgical robotics, digital health platforms, EHR innovation, telemedicine, remote patient monitoring, wearable health tech, pharma technology, precision medicine, genomics platforms, health data interoperability, clinical decision support) ~25%. Always from a physician-executive perspective.',
    forbidden_topics: 'Plastic surgery, aesthetic procedures, reconstructive surgery, facial rejuvenation, any surgical procedures, generic consumer AI (ChatGPT tips, prompt engineering), cryptocurrency, anything not healthcare/medtech',
  },
  drsinabari: {
    allowed_topics: 'Long-form editorial: medicine and technology, physician identity in the AI age, clinical ethics, healthcare policy, medical humanities, the future of the profession, personal essays on practice and innovation',
    forbidden_topics: 'Generic health tips, listicles, short-form clickbait, anything not editorial/opinion in nature',
  },
  sinabariplasticsurgery: {
    allowed_topics: 'Plastic surgery, reconstructive surgery, facial rejuvenation, aesthetic medicine, skin science, surgical technique education, patient safety, recovery guidance',
    forbidden_topics: 'Healthcare AI, enterprise technology, business commentary, anything not related to plastic/reconstructive surgery',
  },
};

const site = SITE_MAP[site_id] || { domain: $json.domain, openclawAgentId: 'publisher-sinabarimd', site_role: 'unknown' };
const topicOverride = TOPIC_OVERRIDES[site_id] || {};

return [{
  json: {
    ...$json,
    ...site,
    openclawAgentId: site.openclawAgentId,
    runtime: {
      site_id,
      domain: site.domain,
      role: topicOverride.allowed_topics ? site.site_role : (profile.role || ''),
      tone: profile.tone || 'professional, analytical, clinician-perspective',
      allowed_topics: topicOverride.allowed_topics || profile.allowed_topics || '',
      forbidden_topics: topicOverride.forbidden_topics || profile.forbidden_topics || '',
    }
  }
}];

const { site_id, domain, research_brief, variation_seed, media_context, seo_context, runtime } = $json;

const mediaStr = (media_context || []).map(m =>
  `- ${(m.type||'').toUpperCase()}: "${m.title}" (${m.url}) — ${m.summary}`
).join('\n') || 'No recent media items.';

const researchStr = research_brief ? `
APPROVED TOPIC: ${research_brief.recommended_topic}
NOVEL ANGLE: ${research_brief.novel_angle || 'not specified'}
AEO QUESTIONS TO ADDRESS:
${(research_brief.aeo_questions || []).map(q => `  - ${q}`).join('\n')}
CITABLE SOURCES (use these, do not fabricate others):
${(research_brief.citable_sources || []).map(s =>
  `  - ${s.title} | ${s.publication} | ${s.date} | ${s.url}`
).join('\n')}
` : 'No research brief provided. Use site profile and media context only.';

const openingMap = {
  narrative: 'Open with a brief narrative or personal observation relevant to the topic.',
  question: 'Open with a specific, direct question that the content will answer.',
  direct_statement: 'Open with a clear, confident factual or opinion statement.',
  data_point: 'Open with a specific statistic or data point, cited from the sources provided.',
};

const DEFAULT_WORD_COUNTS = {
  sinabarimd: 750, sinabari_net: 1200, drsinabari: 1500, sinabariplasticsurgery: 900,
};
const seed = variation_seed || {
  opening_type: 'direct_statement',
  target_word_count: DEFAULT_WORD_COUNTS[site_id] || 900,
  heading_depth: site_id === 'drsinabari' ? 3 : 2,
};

// Retrieve recent dismissal feedback for this site
const genStaticData = $getWorkflowStaticData('global');
const recentFeedback = (genStaticData.dismissal_feedback || [])
  .filter(f => f.site_id === site_id || f.site_id === 'all')
  .slice(-5)
  .map(f => `- Dismissed "${f.dismissed_title}": ${f.feedback}`)
  .join('\n');
const feedbackStr = recentFeedback
  ? `\nOPERATOR FEEDBACK ON PRIOR DRAFTS (avoid these issues):\n${recentFeedback}\n`
  : '';

const prompt = `You are the Content Agent for the Reputation Engine.
Generate a structured YAML article object for: ${domain} (site_id: ${site_id})
Role: ${runtime.role}
Allowed topics: ${runtime.allowed_topics}
Forbidden topics: ${runtime.forbidden_topics}
Tone: ${runtime.tone}
Author: Dr. Sina Bari, MD
Author URL: https://sinabarimd.com/about

VARIATION INSTRUCTIONS:
- ${openingMap[seed.opening_type] || openingMap.direct_statement}
- Target word count: approximately ${seed.target_word_count} words (±15%)
- Use ${seed.heading_depth} levels of heading hierarchy
- Vary paragraph lengths — mix short and long

CONTENT DIRECTION:
${researchStr}

MEDIA CONTEXT (reference where relevant, do not fabricate):
${mediaStr}

OPERATOR FEEDBACK:
${feedbackStr || "No prior feedback."}

SEO CONTEXT:
${seo_context || 'No SEO alerts this week.'}

MANDATORY REQUIREMENTS:
- Include at least one contextual link to https://sinabarimd.com (satellite sites only — skip for sinabarimd site)
- For sinabarimd.com articles: include at least one link to https://sinabarimd.com/about (credentials page) using anchor text that includes "Dr. Sina Bari" or "Stanford-trained surgeon"
- All links to sinabarimd.com should use descriptive anchor text referencing credentials, expertise, or identity — never generic "click here" or "learn more"
- Include a 3-5 item FAQ section at the end of the article.
- FAQ QUALITY RULES:
  - Questions must sound like what a real patient or clinician would type into Google — not generic filler.
  - BAD: "What is plastic surgery?" or "Why is AI important in healthcare?"
  - GOOD: "How does glycolic acid concentration affect peel depth?" or "What happens if a hospital deploys an AI triage tool without clinician oversight?"
  - Each answer must be 2-4 sentences, specific, and directly useful — no padding or restating the question.
  - Include at least one question that names Dr. Sina Bari or references sinabarimd.com (e.g., "What is Dr. Bari's approach to...?")
  - Answers should be extractable by AI Overviews — lead with the direct answer, then add context.
- FAQ format MUST use this exact HTML structure for each Q&A pair:
  <h3>Question text here?</h3>
  <p>Answer text here.</p>
- Do NOT use <strong> for FAQ questions — always use <h3> tags
- Include the author byline: "Dr. Sina Bari, MD" — reference Stanford training where contextually appropriate. Do NOT claim board certification.
- OUTBOUND SOURCE LINKS:
  - Include 2-3 contextual outbound links to authoritative external sources within the article body.
  - If a research_brief is provided and contains citable_sources, you MUST link to at least 2 of them using natural anchor text within the article prose.
  - If no research_brief is provided, include at least 1 outbound link to a reputable source relevant to the article topic (e.g., FDA.gov, NIH, peer-reviewed journals, established tech publications).
  - Never use "click here" or "source" as anchor text. Anchor text must describe what the reader will find.
  - Links must open in the same tab (no target="_blank" needed — these are static pages).
  - Do NOT link to competitor personal brand sites or reputation management services.
- Do not include any forbidden topics

SCIENTIFIC RIGOR (sinabari_net and sinabariplasticsurgery only):
- Bias toward primary literature: prefer citing peer-reviewed journal articles (PubMed, JAMA, NEJM, Lancet, Annals of Surgery, Plastic and Reconstructive Surgery journal) over news articles or opinion pieces.
- When making a clinical claim, reference the specific study, trial name, or publication year — e.g., "A 2024 meta-analysis in the Journal of Clinical and Aesthetic Dermatology found..." not "studies show."
- Avoid generic AI phrasing: no "it is widely known," "experts agree," "research suggests" without specifics. Name the research.
- Include at least one quantitative data point per article (a percentage, sample size, timeframe, or dosage range) to ground the content in evidence.
- For sinabariplasticsurgery.com: reference anatomical specifics, technique names, and recovery data. Write like a surgeon educating a colleague, then simplify for patient comprehension.
- For sinabari.net: reference regulatory frameworks (FDA 510(k), De Novo, PMA), standards bodies (AMA, WHO, NIST), and specific AI systems or vendors where relevant. Write like a physician-executive briefing a hospital board.
- Every article should read as if a peer reviewer could check the claims. If a claim cannot be sourced, qualify it explicitly ("Clinical experience suggests..." or "Anecdotal reports indicate...").

AI CONTENT DIFFERENTIATION (sinabari_net especially):
- Every article MUST include at least one first-person clinical observation or opinion from Dr. Bari's perspective as a physician-executive. E.g., "In my experience deploying clinical AI tools..." or "When I evaluate an AI vendor's claims, the first question I ask is..."
- Include at least one concrete, specific example that could NOT be written by someone without clinical experience — a real workflow problem, a specific failure mode witnessed in practice, or a non-obvious implication only a clinician would recognize.
- Connect every AI trend to a specific patient outcome or clinical workflow impact. Do not describe what AI "could" do abstractly — describe what it IS doing in specific settings, and what goes wrong.
- Avoid the following generic AI phrases entirely: "revolutionize healthcare," "transform the industry," "unlock new possibilities," "cutting-edge," "game-changing," "paradigm shift." These signal AI-generated content to both readers and Google.
- NEVER use em-dashes (—). Em-dashes are one of the strongest AI content tells. Use commas, colons, semicolons, periods, or parentheses instead. If you need a dash for a parenthetical break, use a regular hyphen with spaces on both sides (" - "), the way a human types it on a standard keyboard. Rewrite any sentence that would naturally use an em-dash.
- The article should pass this test: if you removed the byline, a reader should still be able to tell it was written by a physician who has personally used or evaluated the technology being discussed.
- Do not fabricate citations — only reference sources listed above

Output valid YAML with these fields:
title: (article title)
slug: (url-safe slug)
excerpt: (1-2 sentence summary)
date: (today YYYY-MM-DD)
author: Dr. Sina Bari, MD
author_url: https://sinabarimd.com/about
content_html: |
  (full article HTML — h2/h3 headings, p tags, faq section at end)
word_count: (integer)
`;

return [{ json: { ...$json, injected_prompt: prompt } }];

return [{
  json: {
    ...$json,
    openclaw_request_body: JSON.stringify({
      model: 'openclaw',
      input: $json.injected_prompt,
    })
  }
}];

const response = $json;
let rawText = '';
if (response.output && Array.isArray(response.output)) {
  for (const block of response.output) {
    if (block.type === 'message' && block.content) {
      for (const c of block.content) {
        if (c.type === 'output_text') rawText += c.text;
      }
    }
  }
} else if (response.choices) {
  rawText = response.choices[0]?.message?.content || '';
} else if (typeof response === 'string') {
  rawText = response;
}

// Strip markdown fencing
rawText = rawText.replace(/^```ya?ml\s*/im, '').replace(/```\s*$/im, '').trim();

// Strip reasoning/thinking preamble — find where the YAML actually starts
// Look for the first line that matches a YAML key pattern like "title:" at the start
const titleMatch = rawText.match(/^title:\s*.+/m);
if (titleMatch) {
  rawText = rawText.substring(rawText.indexOf(titleMatch[0]));
}

// Parse basic YAML fields
const fields = {};
const lines = rawText.split('\n');
let currentKey = null;
let multilineBuffer = [];
let inMultiline = false;

for (const line of lines) {
  const keyMatch = line.match(/^([\w_]+):\s*(.*)$/);
  if (keyMatch && !line.startsWith(' ') && !line.startsWith('\t')) {
    if (inMultiline && currentKey) {
      fields[currentKey] = multilineBuffer.join('\n').trim();
      multilineBuffer = [];
      inMultiline = false;
    }
    currentKey = keyMatch[1];
    const val = keyMatch[2].trim();
    if (val === '|' || val === '>') {
      inMultiline = true;
    } else {
      fields[currentKey] = val.replace(/^["']|["']$/g, '');
      currentKey = null;
    }
  } else if (inMultiline) {
    multilineBuffer.push(line.replace(/^  /, ''));
  }
}
if (inMultiline && currentKey) {
  fields[currentKey] = multilineBuffer.join('\n').trim();
}

if (!fields.title) throw new Error('Content YAML missing title field');

// Pull pipeline data from upstream node
const origin = $('Build OpenClaw Request').first().json;

return [{
  json: {
    ...origin,
    article: {
      title: fields.title || '',
      slug: (fields.slug || fields.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')),
      excerpt: fields.excerpt || '',
      date: fields.date || new Date().toISOString().split('T')[0],
      author: fields.author || 'Dr. Sina Bari, MD',
      author_url: fields.author_url || 'https://sinabarimd.com/about',
      content_html: fields.content_html || '',
      word_count: parseInt(fields.word_count) || 0,
    },
    raw_yaml: rawText,
  }
}];

const staticData = $getWorkflowStaticData('global');
const drafts = staticData.drafts || {};
const { site_id, article } = $json;

const draftId = `${site_id}_${Date.now()}`;
drafts[draftId] = {
  draft_id: draftId,
  site_id,
  generated_at: new Date().toISOString(),
  status: 'pending_review',
  article,
  research_brief: $json.research_brief || null,
  variation_seed: $json.variation_seed || null,
};
staticData.drafts = drafts;

return [{
  json: {
    ...$json,
    draft_id: draftId,
    status: 'pending_review',
    review_instruction: `Review draft at GET /webhook/list-drafts. Approve by POST to /webhook/approve-draft with { draft_id: "${draftId}", site_id: "${site_id}" }`,
  }
}];

const staticData = $getWorkflowStaticData('global');
const drafts = staticData.drafts || {};

const pending = Object.values(drafts).filter(d => d.status === 'pending_review');
const approved = Object.values(drafts).filter(d => d.status === 'approved');

return [{
  json: {
    generated_at: new Date().toISOString(),
    instructions: 'POST to /webhook/approve-draft with { draft_id, site_id } to approve. Then POST to /webhook/publish-draft to deploy.',
    pending_count: pending.length,
    approved_count: approved.length,
    pending_drafts: pending.map(d => ({
      draft_id: d.draft_id,
      site_id: d.site_id,
      generated_at: d.generated_at,
      title: d.article?.title,
      excerpt: d.article?.excerpt,
      word_count: d.article?.word_count,
      slug: d.article?.slug,
    })),
    approved_drafts: approved.map(d => ({
      draft_id: d.draft_id,
      site_id: d.site_id,
      title: d.article?.title,
      approved_at: d.approved_at,
    })),
  }
}];

const staticData = $getWorkflowStaticData('global');
const drafts = staticData.drafts || {};
const draft_id = $json.query?.draft_id || $json.draft_id;

if (!draft_id) {
  return [{ json: { error: 'draft_id query param required' } }];
}

const draft = drafts[draft_id];
if (!draft) {
  return [{ json: { error: 'Draft not found', draft_id } }];
}

return [{ json: draft }];

const body = $json.body || $json;
const { draft_id, title, excerpt, content_html, site_id, status } = body;

if (!draft_id) {
  return [{ json: { error: true, message: 'draft_id is required' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
const draft = staticData.drafts[draft_id];

if (!draft) {
  return [{ json: { error: true, message: 'Draft not found: ' + draft_id } }];
}

// Track edit history
if (!draft.edit_history) draft.edit_history = [];
const changedFields = [
  ...(title !== undefined ? ['title'] : []),
  ...(excerpt !== undefined ? ['excerpt'] : []),
  ...(content_html !== undefined ? ['content_html'] : []),
  ...(site_id !== undefined && site_id !== draft.site_id ? ['site_id'] : []),
    ...(status !== undefined ? ['status'] : []),
];
draft.edit_history.push({
  edited_at: new Date().toISOString(),
  fields_changed: changedFields,
  ...(site_id !== undefined && site_id !== draft.site_id ? { rerouted_from: draft.site_id, rerouted_to: site_id } : {}),
});

// Reroute site if changed
if (site_id !== undefined && site_id !== draft.site_id) {
  const old_site = draft.site_id;
  draft.site_id = site_id;

  // Update draft_id to reflect new site
  const new_draft_id = site_id + '_' + draft_id.split('_').pop();
  delete staticData.drafts[draft_id];
  draft.draft_id = new_draft_id;
  staticData.drafts[new_draft_id] = draft;

  // Update author_url to always point to sinabarimd.com
  draft.article.author_url = 'https://sinabarimd.com/about';
}

// Apply edits
if (title !== undefined) draft.article.title = title;
if (excerpt !== undefined) draft.article.excerpt = excerpt;
if (content_html !== undefined) draft.article.content_html = content_html;

// Recompute word count if content changed
if (content_html !== undefined) {
  const text = content_html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  draft.article.word_count = text.split(' ').filter(w => w.length > 0).length;
}

// Recompute slug if title changed
if (title !== undefined) {
  draft.article.slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

draft.last_edited = new Date().toISOString();

// Update status if provided (e.g., 'published' after deploy)
if (status) {
  draft.status = status;
  if (status === 'published') draft.published_at = new Date().toISOString();
}

return [{ json: {
  success: true,
  draft_id: draft.draft_id,
  site_id: draft.site_id,
  title: draft.article.title,
  excerpt: draft.article.excerpt,
  word_count: draft.article.word_count,
  slug: draft.article.slug,
  edit_count: draft.edit_history.length,
  last_edited: draft.last_edited,
} }];

const body = $json.body || $json;
const { draft_id } = body;

if (!draft_id) {
  return [{ json: { error: true, message: 'draft_id is required' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
const draft = staticData.drafts[draft_id];

if (!draft) {
  return [{ json: { error: true, message: 'Draft not found: ' + draft_id } }];
}

draft.status = 'approved';
draft.approved_at = new Date().toISOString();
staticData.drafts[draft_id] = draft;

return [{ json: {
  success: true,
  draft_id,
  site_id: draft.site_id,
  title: draft.article.title,
  status: 'approved',
  approved_at: draft.approved_at,
} }];

const body = $json.body || $json;
const { draft_id, feedback } = body;

if (!draft_id) {
  return [{ json: { error: true, message: 'draft_id is required' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.drafts) staticData.drafts = {};
if (!staticData.dismissal_feedback) staticData.dismissal_feedback = [];

const draft = staticData.drafts[draft_id];
if (!draft) {
  return [{ json: { error: true, message: 'Draft not found: ' + draft_id } }];
}

// Store feedback for future drafting context
if (feedback && feedback.trim()) {
  staticData.dismissal_feedback.push({
    site_id: draft.site_id,
    dismissed_title: draft.article?.title || '',
    feedback: feedback.trim(),
    dismissed_at: new Date().toISOString(),
  });
  // Keep last 20 feedback items
  if (staticData.dismissal_feedback.length > 20) {
    staticData.dismissal_feedback = staticData.dismissal_feedback.slice(-20);
  }
}

// Remove the draft
const title = draft.article?.title || draft_id;
const site_id = draft.site_id;
delete staticData.drafts[draft_id];

return [{ json: {
  success: true,
  draft_id,
  site_id,
  title,
  feedback: feedback || null,
  message: 'Draft dismissed' + (feedback ? ' with feedback recorded' : ''),
  total_feedback: staticData.dismissal_feedback.length,
} }];

const staticData = $getWorkflowStaticData('global');
const body = $json.body || $json;
const { draft_id, suggestions } = body;

if (!draft_id || !suggestions) {
  return [{ json: { success: false, error: 'Required: draft_id, suggestions' } }];
}

const draft = staticData.drafts?.[draft_id];
if (!draft) {
  return [{ json: { success: false, error: 'Draft not found: ' + draft_id } }];
}

const article = draft.article || {};
const agentMap = {"sinabarimd": "publisher-sinabarimd", "sinabari_net": "publisher-sinabari-net", "drsinabari": "publisher-drsinabari", "sinabariplasticsurgery": "publisher-sinabariplasticsurgery"};
const prompt = `You are rewriting an article draft based on operator feedback.

CURRENT DRAFT:
Title: ${article.title}
Excerpt: ${article.excerpt}
Site: ${draft.site_id}

Content:
${article.content_html}

OPERATOR SUGGESTIONS FOR REWRITE:
${suggestions}

RULES:
- Preserve the topic, site assignment, and general structure unless the suggestions explicitly ask to change them.
- Apply the suggestions thoughtfully - improve the draft, don't just mechanically insert changes.
- Maintain the same first-person physician voice and clinical perspective.
- NEVER use em-dashes. Use commas, colons, semicolons, periods, or " - " (space-dash-space) instead.
- NEVER claim board certification.
- Keep approximately the same word count unless suggestions ask for more or less.
- Output valid YAML with these fields:
title: (revised title)
slug: (url-safe slug)
excerpt: (1-2 sentence excerpt)
content_html: |
  (full article HTML)
word_count: (approximate)`;

return [{ json: {
  draft_id,
  site_id: draft.site_id,
  openclawAgentId: agentMap[draft.site_id] || 'publisher-drsinabari',
  rewrite_body: JSON.stringify({
    model: 'openclaw',
    input: prompt,
  }),
} }];

const staticData = $getWorkflowStaticData('global');
const upstream = $('Build Rewrite Prompt').first().json;
const draft_id = upstream.draft_id;

const output = $json.output || [];
let text = '';
for (const block of output) {
  for (const part of (block.content || [])) {
    if (part.text) text += part.text;
  }
}

// Parse YAML response
text = text.replace(/^```yaml\s*/m, '').replace(/^```\s*$/m, '').trim();

let title = '', excerpt = '', content_html = '', slug = '', word_count = 0;
try {
  // Extract fields from YAML
  const titleM = text.match(/^title:\s*(.+)$/m);
  const slugM = text.match(/^slug:\s*(.+)$/m);
  const excerptM = text.match(/^excerpt:\s*(.+)$/m);
  const wcM = text.match(/^word_count:\s*(\d+)/m);
  title = titleM ? titleM[1].replace(/^["']|["']$/g, '').trim() : '';
  slug = slugM ? slugM[1].trim() : '';
  excerpt = excerptM ? excerptM[1].replace(/^["']|["']$/g, '').trim() : '';
  word_count = wcM ? parseInt(wcM[1]) : 0;

  // Extract content_html (everything between content_html: | and the next top-level key or end)
  const contentM = text.match(/content_html:\s*\|\n([\s\S]*?)(?=\n\w+:|$)/);
  if (contentM) {
    content_html = contentM[1].split('\n').map(l => l.replace(/^  /, '')).join('\n').trim();
  }
} catch(e) {
  return [{ json: { success: false, error: 'Failed to parse rewrite: ' + e.message, raw: text.slice(0, 500) } }];
}

if (!content_html || content_html.length < 100) {
  return [{ json: { success: false, error: 'Rewrite produced empty content', raw: text.slice(0, 500) } }];
}

// Update the draft
const draft = staticData.drafts[draft_id];
const article = draft.article || {};
article.title = title || article.title;
article.excerpt = excerpt || article.excerpt;
article.slug = slug || article.slug;
article.content_html = content_html;
article.word_count = word_count || article.word_count;
draft.article = article;
draft.rewrite_count = (draft.rewrite_count || 0) + 1;
draft.last_rewrite = new Date().toISOString();
draft.status = 'pending_review';

return [{ json: {
  success: true,
  draft_id,
  title: draft.article.title,
  word_count: draft.article.word_count,
  rewrite_count: draft.rewrite_count,
} }];
